public class ExInheritance {
    static class Base extends Exception { Base(String m){super(m);} }
    static class Child extends Base { Child(String m){super(m);} }
    public static void main(String[] args) {
        try {
            throw new Child("child ex");
        } catch (Base e) {
            System.out.println("Base caught: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("Exception caught");
        }
    }
}
